mapper.select:
SELECT session_id, user_id, guest_flag, title, msg_count, last_msg_id, last_active, create_time
FROM ai_chat_session
WHERE session_id = #{sessionId}
  AND user_id = #{userId}
LIMIT 1

mapper.insert:
